// runDuration returns a human-readable duration string for a run.
// fmtElapsed formats a float64 elapsed-seconds value for display.
// Shows ms for values < 1s, seconds otherwise.
func fmtElapsed(elapsedS float64) string {
	if elapsedS < 0.001 {
		return "< 1ms"
	}
	if elapsedS < 1.0 {
		return fmt.Sprintf("%.0fms", elapsedS*1000)
	}
	return fmt.Sprintf("%.1fs", elapsedS)
}

func runDuration(r runlog.RunRow) string {
	if r.FinishedAt == nil {
		return "running..."
	}
	dur := r.FinishedAt.Sub(r.StartedAt)
	if dur < time.Millisecond {
		return "< 1ms"
	}
	if dur < time.Second {
		return fmt.Sprintf("%.0fms", float64(dur.Milliseconds()))
	}
	if dur < time.Minute {
		return fmt.Sprintf("%.1fs", dur.Seconds())
	}
	return fmt.Sprintf("%.0fm %0.0fs", dur.Minutes(), math.Mod(dur.Seconds(), 60))
}

