// runBadgeIntent returns the appropriate BadgeIntent for a status string.
func runBadgeIntent(status string) ui.BadgeIntent {
	switch status {
	case "pass":
		return ui.BadgeSuccess
	case "fail":
		return ui.BadgeError
	case "skip":
		return ui.BadgeWarning
	case "running":
		return ui.BadgeInfo
	default:
		return ui.BadgeNeutral
	}
}

