func optInt64OrDash(v *int64) string {
	if v == nil {
		return "-"
	}
	return fmt.Sprintf("%d", *v)
}

func optCostOrDash(v *float64) string {
	if v == nil {
		return "-"
	}
	return fmt.Sprintf("$%.4f", *v)
}

func statsGridClass(cols int) string {
	switch cols {
	case 2:
		return "grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6"
	case 3:
		return "grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 mb-6"
	case 5:
		return "grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4 mb-6"
	default:
		return "grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-6"
	}
}

func optStrOrDash(v *string) string {
	if v == nil || *v == "" {
		return "-"
	}
	return *v
}

func runExitCode(r runlog.RunRow) string {
	if r.FinishedAt == nil {
		return "-"
	}
	if r.Skipped {
		return "0 (skipped)"
	}
	if r.Passed != nil && *r.Passed {
		return "0"
	}
	return "1"
}

