func trendDotClass(points []trendPoint) string {
	if len(points) < 4 {
		return "text-base-content/70"
	}
	half := len(points) / 2
	var first, second float64
	for i := 0; i < half; i++ {
		first += points[i].DurationMS
	}
	for i := half; i < len(points); i++ {
		second += points[i].DurationMS
	}
	firstAvg := first / float64(half)
	secondAvg := second / float64(len(points)-half)
	if secondAvg > firstAvg*1.1 {
		return "text-error"
	}
	if secondAvg < firstAvg*0.9 {
		return "text-success"
	}
	return "text-base-content/70"
}

func hasCostData(r runlog.RunRow) bool {
	return (r.InputTokens != nil && *r.InputTokens > 0) ||
		(r.OutputTokens != nil && *r.OutputTokens > 0) ||
		(r.CostUSD != nil && *r.CostUSD > 0)
}

func boolToOneZeroStr(b bool) string {
	if b {
		return "1"
	}
	return ""
}

func redactEnvValue(v string) string {
	if len(v) < 8 {
		return strings.Repeat("*", len(v))
	}
	return v[:4] + strings.Repeat("*", len(v)-8) + v[len(v)-4:]
}

// splitTestName splits a dogfood-format test name into (filePart, testNamePart).
// Format: "{category} / {fullPath}" where category contains file + describe path.
// If no separator found, returns ("", fullName).
func testNameFile(fullName string) string {
	if idx := strings.Index(fullName, " / "); idx >= 0 {
		return fullName[:idx]
	}
	return ""
}

func testNameOnly(fullName string) string {
	if idx := strings.Index(fullName, " / "); idx >= 0 {
		return fullName[idx+3:]
	}
	return fullName
}

